struct DmiBus
{
  virtual ~DmiBus() = default;
  virtual void write(uint8_t reg, uint32_t value) = 0;
  virtual auto read(uint8_t reg) -> uint32_t = 0;
};

class ResumeDriver
{
public:
  static constexpr uint8_t kData0      = 0x04;
  static constexpr uint8_t kData1      = 0x05;
  static constexpr uint8_t kDmcontrol  = 0x10;
  static constexpr uint8_t kDmstatus   = 0x11;
  static constexpr uint8_t kAbstractcs = 0x16;
  static constexpr uint8_t kCommand    = 0x17;

  static constexpr uint16_t kCsrDpc      = 0x7B1;
  static constexpr uint16_t kCsrMstatus  = 0x300;
  static constexpr uint16_t kCsrMtvec    = 0x305;
  static constexpr uint16_t kCsrVstart   = 0x008;
  static constexpr uint16_t kCsrVxsat    = 0x009;
  static constexpr uint16_t kCsrVxrm     = 0x00A;
  static constexpr uint16_t kCsrVcsr     = 0x00F;
  static constexpr uint16_t kCsrVtype    = 0xC21;
  static constexpr uint16_t kCsrVl       = 0xC20;

  static constexpr uint32_t kDmcontrolDmactive  = 1u << 0;
  static constexpr uint32_t kDmcontrolResumereq = 1u << 30;
  static constexpr uint32_t kDmcontrolHaltreq   = 1u << 31;

  static constexpr uint32_t kDmstatusAllhalted    = 1u << 9;
  static constexpr uint32_t kDmstatusAllresumeack = 1u << 17;

  static constexpr uint32_t kAbstractcsBusy        = 1u << 12;
  static constexpr uint32_t kAbstractcsCmderrMask  = 0x7u << 8;

  static constexpr unsigned kPollIterations = kDmiPollIterations;

  explicit ResumeDriver(DmiBus& bus)
      : bus_{bus}
  {}

  void resume(const hybrid_state_v1& state)
  {
    if (state.magic != HYBRID_STATE_MAGIC)
      throw std::runtime_error("ResumeDriver::resume: bad magic");
    if (state.version != HYBRID_STATE_VERSION)
      throw std::runtime_error("ResumeDriver::resume: unsupported version");

    // dmactive must transition 0->1 in its own write before any other
    // DMCONTROL bit is honored (RISC-V Debug Spec).
    bus_.write(kDmcontrol, kDmcontrolDmactive);
    request_halt();
    poll_until_set(bus_, kDmstatus, kDmstatusAllhalted, "ResumeDriver halt");

    // Tier-A V CSR restore (before GPRs: PB fallback uses x5 as scratch;
    // the GPR loop overwrites x5 afterward so state is preserved).
    if (state.flags & HYBRID_FLAG_V) {
      // mstatus: only write when VS field is non-zero (restore previous VS
      // mode; leave at Off when the state was Off to avoid unnecessary DM
      // abstract-write failures on implementations that reject mstatus).
      if (state.mstatus & 0x600u)
        write_csr_abstract_or_pb(kCsrMstatus, state.mstatus);
      // Tier-B: vtype+vl via vsetvl x0,x5,x6 in PB.
      // Direct csrrw to vtype sets vill; vl is read-only. Stage operands in
      // scratch GPRs x5(vl) and x6(vtype) then let vsetvl set both atomically.
      // x5/x6 are overwritten by the GPR loop below, so no leakage.
      write_64bit_register(regno_gpr(5), state.vl);
      write_64bit_register(regno_gpr(6), state.vtype);
      const std::array<uint32_t, 1> pb_vsetvl = { encode_vsetvl(0, 5, 6) };
      exec_progbuf(bus_, std::span<const uint32_t>{pb_vsetvl});
      // vstart must come AFTER vsetvl: vsetvl resets vstart to 0.
      write_csr_abstract_or_pb(kCsrVstart, state.vstart);
      write_csr_abstract_or_pb(kCsrVxsat,  state.vxsat);
      write_csr_abstract_or_pb(kCsrVxrm,   state.vxrm);
      write_csr_abstract_or_pb(kCsrVcsr,   state.vcsr);
    }

    // GPRs + DPC (after V CSRs so PB scratch x5 is safe to overwrite).
    for (uint16_t i = 1; i < 32; ++i)
      write_64bit_register(regno_gpr(i), state.gpr[i]);
    write_64bit_register(regno_csr(kCsrDpc), state.pc);

    write_csr_tolerant(kCsrMtvec, state.mtvec);

    clear_cmderr_if_set();

inline auto connect_loopback(uint16_t port,
                             std::chrono::milliseconds timeout,
                             pid_t child_pid = -1) -> int
{
  const auto deadline = std::chrono::steady_clock::now() + timeout;
  while (std::chrono::steady_clock::now() < deadline) {
    const int s = ::socket(AF_INET, SOCK_STREAM, 0);
    if (s < 0)
      throw std::runtime_error("connect_loopback: socket");
    sockaddr_in addr{};
    addr.sin_family      = AF_INET;
    addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
    addr.sin_port        = htons(port);
    if (::connect(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) == 0)
      return s;
    ::close(s);
    if (child_pid > 0) {
      int wstat = 0;
      if (::waitpid(child_pid, &wstat, WNOHANG) == child_pid) {
        int status = -1;
        if (WIFEXITED(wstat)) status = WEXITSTATUS(wstat);
        else if (WIFSIGNALED(wstat)) status = 128 + WTERMSIG(wstat);
        throw ChildExitedDuringConnect{status};
      }
    }
    std::this_thread::sleep_for(std::chrono::milliseconds(20));
  }
  throw std::runtime_error("connect_loopback: timed out waiting for QEMU "
                           "gdbstub");
}

inline auto spawn_qemu(const std::string& binary,
                       const std::string& elf,
                       uint16_t gdb_port,
                       const std::string& shared_mem_path = {},
                       uint64_t shared_mem_size = 0) -> pid_t
{
  const pid_t pid = ::fork();
  if (pid < 0)
    throw std::runtime_error(std::string{"spawn_qemu: fork: "}
                             + std::strerror(errno));
  if (pid == 0) {
    // Detach the child from the caller's tty. -nographic makes QEMU's
    // chardev backend tcsetattr() stdin into raw mode; if the caller is
    // launched from a non-foreground process group (e.g. under timeout(1)),
    // that touch raises SIGTTOU/SIGTTIN and stops QEMU 2, hanging vsim's
    // waitpid. /dev/null sidesteps the tty entirely.
    const int devnull = ::open("/dev/null", O_RDONLY | O_CLOEXEC);
    if (devnull >= 0) {
      ::dup2(devnull, STDIN_FILENO);
      ::close(devnull);
    }

    const std::string gdb_arg = "tcp::" + std::to_string(gdb_port);
    const std::string mem_obj = "memory-backend-file,id=mem,share=on,mem-path="
                              + shared_mem_path
                              + ",size=" + std::to_string(shared_mem_size);
    std::vector<const char*> argv;
    argv.push_back(binary.c_str());
    if (!shared_mem_path.empty()) {
      argv.push_back("-object");
      argv.push_back(mem_obj.c_str());
      argv.push_back("-machine");
      argv.push_back("andes_ae350,memory-backend=mem");
    } else {
      argv.push_back("-M");
      argv.push_back("virt");
    }
    // -cpu andes-ax45mpv,vlen=512: matches QEMU 1's CPU and the vsim RTL
    // build (NDS_VLEN 512). Without this, QEMU 2 defaults to plain rv64
    // (no V), mstatus.VS becomes read-only zero, and vsetvli traps with
    // illegal-instruction as soon as a V-using fixture's Phase 3 runs.
    // Andes vendor CSRs touched by the runtime crt0 (mcache_ctl, mmisc_ctl,
    // ...) are also gated here.
    argv.push_back("-cpu");
    argv.push_back("andes-ax45mpv,vlen=512");
    argv.push_back("-bios");
    argv.push_back("none");
    argv.push_back("-nographic");

    argv.push_back("-nographic");
    argv.push_back("-semihosting-config");
    argv.push_back("enable=on,target=native");
    // In tier-2 (shared mmap), .text/.rodata/.data are already in the
    // shared file from QEMU 1's -kernel; re-loading here would zero
    // .bss and reset .data, destroying memory written in phase 2. The
    // resume PC is restored via gdbstub P32 below, so the ELF entry
    // point is irrelevant. Tier-1 (no shared mmap) still needs -kernel
    // to populate QEMU 2's private RAM.
    if (shared_mem_path.empty()) {
      argv.push_back("-kernel");
      argv.push_back(elf.c_str());
    }
    argv.push_back("-gdb");
    argv.push_back(gdb_arg.c_str());
    argv.push_back("-S");
    argv.push_back(nullptr);

    ::execv(binary.c_str(), const_cast<char* const*>(argv.data()));
    std::fprintf(stderr, "exec %s: %s\n", binary.c_str(),
                 std::strerror(errno));
    ::_exit(127);
  }
  return pid;
}

